  col+=d2*vec3(0.015,0.018,0.022); // cool dark blue-grey
  col+=d3*vec3(0.022,0.016,0.012); // amber shadow
  col+=d4*vec3(0.012,0.015,0.020); // slate
  col+=n*vec3(0.008,0.006,0.005);  // noise detail

